def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import pygmo as pg
    import random
    import heapq

    n, d = points.shape
    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    hv_cache = {}

    def compute_hv(indices):
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv = 0.0
        else:
            hv = pg.hypervolume(points[list(indices)]).compute(reference_point)
        hv_cache[key] = hv
        return hv

    # Phase 1: Greedy initialization with random restarts
    def greedy_init(seed_set=None):
        if seed_set is None:
            selected = set()
            # Start with random point
            start = random.randint(0, n-1)
            selected.add(start)
        else:
            selected = set(seed_set)

        while len(selected) < k:
            current_hv = compute_hv(selected)
            best_contrib = -float('inf')
            best_idx = -1
            remaining = [i for i in range(n) if i not in selected]
            sample_size = min(25, len(remaining))
            candidates = random.sample(remaining, sample_size)
            for idx in candidates:
                new_set = selected | {idx}
                new_hv = compute_hv(new_set)
                contrib = new_hv - current_hv
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx
            if best_idx != -1:
                selected.add(best_idx)
            else:
                if remaining:
                    selected.add(random.choice(remaining))
        return selected

    # Create initial diverse population using greedy with different seeds
    population = []
    # Pure greedy from random start
    population.append(greedy_init())
    # Random subset
    population.append(set(random.sample(range(n), k)))
    # Greedy from another random start
    population.append(greedy_init())

    # Phase 2: Beam search with expansion and pruning
    beam_width = 10
    beam = []
    for subset in population:
        hv = compute_hv(subset)
        heapq.heappush(beam, (hv, subset))
        if len(beam) > beam_width:
            heapq.heappop(beam)  # keep only top beam_width

    iterations = 15
    for _ in range(iterations):
        new_beam = list(beam)
        for _, subset in beam:
            # Compute contributions for current subset
            subset_hv = compute_hv(subset)
            contributions = {}
            for idx in subset:
                temp = subset - {idx}
                contributions[idx] = subset_hv - compute_hv(temp)

            # Sort by contribution (ascending)
            sorted_low = sorted(contributions.items(), key=lambda x: x[1])
            # Take worst 3 points
            worst_points = [item[0] for item in sorted_low[:min(3, len(sorted_low))]]

            # Generate expansions by swapping each worst point
            for worst in worst_points:
                remaining = set(range(n)) - subset
                if not remaining:
                    continue

                # Sample high-potential replacements
                sample_size = min(20, len(remaining))
                candidates = random.sample(list(remaining), sample_size)

                for cand in candidates:
                    new_subset = (subset - {worst}) | {cand}
                    new_hv = compute_hv(new_subset)
                    heapq.heappush(new_beam, (new_hv, new_subset))
                    if len(new_beam) > beam_width * 2:
                        heapq.heappop(new_beam)

        # Prune to beam_width
        beam = heapq.nlargest(beam_width, new_beam)

    # Get best from beam
    best_hv, best_set = max(beam, key=lambda x: x[0])

    # Phase 3: Exhaustive pairwise swap refinement
    improvement = True
    while improvement:
        improvement = False
        # Compute contributions
        contributions = {}
        for idx in best_set:
            temp = best_set - {idx}
            contributions[idx] = best_hv - compute_hv(temp)

        # Sort by contribution (ascending)
        sorted_points = sorted(contributions.items(), key=lambda x: x[1])
        remaining = set(range(n)) - best_set

        # Try swapping each low-contribution point with all possible replacements
        for idx_in, _ in sorted_points:
            best_swap = None
            best_gain = 0
            for idx_out in remaining:
                new_set = (best_set - {idx_in}) | {idx_out}
                new_hv = compute_hv(new_set)
                gain = new_hv - best_hv
                if gain > best_gain:
                    best_gain = gain
                    best_swap = idx_out

            if best_swap is not None and best_gain > 1e-10:
                best_set.remove(idx_in)
                best_set.add(best_swap)
                best_hv += best_gain
                improvement = True
                break  # Restart with updated contributions

    selected_indices = list(best_set)
    return points[selected_indices]

def HSS(points, k: int, reference_point) -> np.ndarray:
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape

    # 缓存超体积计算
    hv_cache = {}

    def compute_hv(indices):
        key = tuple(sorted(indices))
        if key not in hv_cache:
            if not indices:
                hv_cache[key] = 0.0
            else:
                hv = pg.hypervolume(points[list(indices)])
                hv_cache[key] = hv.compute(reference_point)
        return hv_cache[key]

    # 1. 基于贡献的贪心初始化
    def greedy_by_contributions():
        selected = set()
        contributions = {}

        # 初始贡献：单个点的超体积
        for i in range(n):
            contributions[i] = compute_hv([i])

        while len(selected) < k:
            # 选择贡献最大的点
            best_idx = max((idx for idx in range(n) if idx not in selected), 
                          key=lambda x: contributions[x], default=None)

            if best_idx is None:
                # 如果没有候选点，随机选择一个
                remaining = [i for i in range(n) if i not in selected]
                if remaining:
                    best_idx = random.choice(remaining)
                else:
                    break

            selected.add(best_idx)

            # 更新剩余点的贡献估计
            if len(selected) < k:
                for i in range(n):
                    if i not in selected:
                        # 近似计算新贡献：与当前集合的边际贡献
                        new_set = list(selected) + [i]
                        old_hv = compute_hv(list(selected))
                        new_hv = compute_hv(new_set)
                        contributions[i] = new_hv - old_hv

        return list(selected)

    # 2. 迭代删除-添加优化
    def iterative_removal_addition(initial_set):
        current_set = set(initial_set)
        best_hv = compute_hv(list(current_set))

        improved = True
        while improved:
            improved = False

            # 删除阶段：移除贡献最小的点
            if len(current_set) > 1:
                worst_contrib = float('inf')
                worst_point = None

                for idx in current_set:
                    temp_set = current_set - {idx}
                    contrib = best_hv - compute_hv(list(temp_set))
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_point = idx

                # 尝试移除贡献最小的点
                if worst_point is not None:
                    candidate_set = current_set - {worst_point}

                    # 添加阶段：寻找最佳替换点
                    best_add = None
                    best_add_hv = -float('inf')

                    for i in range(n):
                        if i not in candidate_set:
                            new_set = list(candidate_set) + [i]
                            new_hv = compute_hv(new_set)
                            if new_hv > best_add_hv:
                                best_add_hv = new_hv
                                best_add = i

                    if best_add is not None and best_add_hv > best_hv:
                        candidate_set.add(best_add)
                        current_set = candidate_set
                        best_hv = best_add_hv
                        improved = True

            # 如果没有改进，尝试随机扰动
            if not improved and len(current_set) == k:
                # 随机交换两个点
                for _ in range(min(10, n)):
                    remove_idx = random.choice(list(current_set))
                    candidate_set = current_set - {remove_idx}

                    available = [i for i in range(n) if i not in candidate_set]
                    if not available:
                        continue

                    add_idx = random.choice(available)
                    new_set = list(candidate_set) + [add_idx]
                    new_hv = compute_hv(new_set)

                    if new_hv > best_hv:
                        current_set = set(new_set)
                        best_hv = new_hv
                        improved = True
                        break

        return list(current_set)

    # 3. 邻域搜索优化
    def neighborhood_search(current_set):
        best_set = current_set.copy()
        best_hv = compute_hv(best_set)

        # 尝试所有可能的单点替换
        for i in range(len(best_set)):
            for j in range(n):
                if j in best_set:
                    continue

                new_set = best_set.copy()
                new_set[i] = j
                new_hv = compute_hv(new_set)

                if new_hv > best_hv:
                    best_set = new_set
                    best_hv = new_hv

        return best_set

    # 主算法流程
    # 步骤1: 贪心初始化
    initial_set = greedy_by_contributions()

    # 步骤2: 迭代删除-添加优化
    improved_set = iterative_removal_addition(initial_set)

    # 步骤3: 邻域搜索
    final_set = neighborhood_search(improved_set)

    # 确保返回k个点
    if len(final_set) != k:
        # 如果不足k个点，用贪心补充
        current = set(final_set)
        while len(current) < k:
            best_contrib = -float('inf')
            best_idx = None

            for i in range(n):
                if i not in current:
                    new_set = list(current) + [i]
                    contrib = compute_hv(new_set) - compute_hv(list(current))
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = i

            if best_idx is not None:
                current.add(best_idx)
            else:
                break

        final_set = list(current)

    return points[final_set]

